package main

import (
	"fmt"

	"github.com/malcolmston/redis"
)

func main() {
	s := redis.New()
	s.Set("greeting", "hello", redis.SetOptions{})

	v, ok, _ := s.Get("greeting")
	fmt.Println(v, ok)

	_, ok, _ = s.Get("absent")
	fmt.Println(ok)

}
